   FROM ((((((((("getStockPricesYahooHistory"(p_target_date) a
     LEFT JOIN ( SELECT ed.symbol,
            (
                CASE
                    WHEN (ed.earnings_date ~~ '%.%.%'::text) THEN ((((substr(ed.earnings_date, 7, 4) || '-'::text) || substr(ed.earnings_date, 4, 2)) || '-'::text) || substr(ed.earnings_date, 1, 2))
                    ELSE NULL::text
                END)::date AS earnings_date
           FROM "getEarningDatesHistory"(p_target_date) ed) b ON ((a.symbol = b.symbol)))
     LEFT JOIN "getAnalystPriceTargetsHistory"(p_target_date) c ON ((a.symbol = c.symbol)))
     LEFT JOIN "getStockImpliedVolatilityMassiveHistory"(p_target_date) d ON ((a.symbol = d.symbol)))
     LEFT JOIN "getStockVolatilityHistory"(p_target_date) e ON ((a.symbol = e.symbol)))
     LEFT JOIN "getDividendDataHistory"(p_target_date) f ON ((a.symbol = f.symbol)))
     LEFT JOIN ( SELECT "OptionDataMassiveMasterData".symbol,
            min("OptionDataMassiveMasterData".from_date) AS from_date
           FROM "OptionDataMassiveMasterData"
          GROUP BY "OptionDataMassiveMasterData".symbol) g ON ((a.symbol = g.symbol)))
     LEFT JOIN ( SELECT "StockPricesYahooMasterData".symbol,
            min("StockPricesYahooMasterData".from_date) AS from_date
           FROM "StockPricesYahooMasterData"
          GROUP BY "StockPricesYahooMasterData".symbol) h ON ((a.symbol = h.symbol)))
     LEFT JOIN "getFundamentalDataHistory"(p_target_date) i ON ((a.symbol = i.symbol)))
     LEFT JOIN "getTechnicalIndicatorsCalculatedHistory"(p_target_date) j ON ((a.symbol = j.symbol)));
